import React, { useState, useEffect } from 'react';
import axios from 'axios';

function ClientDashboard() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const fetchAllProjects = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setProjects(res.data);
      setLoading(false);
    } catch (err) {
      setError("❌ डेटा लोड करने में विफल। कृपया सुनिश्चित करें कि सर्वर चल रहा है।");
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAllProjects();
  }, []);

  const handleRevisionRequest = async (id) => {
    const revisionMsg = document.getElementById(`rev-${id}`).value;
    if (!revisionMsg.trim()) return alert("कृपया बताएं कि आपको क्या बदलाव चाहिए!");

    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, {
        revisionsRequested: revisionMsg
      });
      alert("✅ आपका अनुरोध सफलतापूर्वक भेज दिया गया है!");
      document.getElementById(`rev-${id}`).value = ""; 
      fetchAllProjects(); 
    } catch (err) {
      alert("❌ अनुरोध भेजने में विफल।");
    }
  };

  // --- मुख्य सुधार: पेमेंट डिस्प्ले लॉजिक ---
  const renderPaymentStatus = (proj) => {
    // डेटा को शुद्ध नंबर में बदलें (ताकि गणित सही हो)
    const total = Number(proj.totalBudget) || 0;
    const paid = Number(proj.advancePaid) || 0;
    const balance = total - paid;
    
    // १. अगर बजट सेट नहीं है (₹0)
    if (total === 0) {
      return (
        <div className="text-center p-2 rounded bg-light border mt-2">
          <small className="fw-bold text-muted">STATUS: BUDGET NOT SET</small>
        </div>
      );
    }

    // २. अगर पूरी फीस भर दी गई है (Direct Full Payment)
    if (total > 0 && balance <= 0) {
      return (
        <div className="text-center p-3 rounded-3 mt-2 shadow-sm" style={{backgroundColor: '#eafff5', border: '1px solid #27ae60'}}>
          <div className="fw-bold text-success" style={{fontSize: '0.85rem'}}>
            ✅ DIRECT FULL FEES PAID
          </div>
          <div className="text-muted mt-1" style={{fontSize: '11px'}}>Total Received: ₹{paid}</div>
        </div>
      );
    }

    // ३. अगर पैसे बाकी हैं (बाकी सभी केसेस में यह दिखेगा)
    return (
      <div className="mt-3">
        <div className="d-flex justify-content-between mb-1">
            <span className="small text-muted">Total Budget:</span>
            <span className="fw-bold">₹{total}</span>
        </div>
        <div className="d-flex justify-content-between mb-2">
            <span className="small text-muted">Advance Paid:</span>
            <span className="fw-bold text-success">₹{paid}</span>
        </div>
        <div className="pt-2 border-top d-flex justify-content-between align-items-center">
          <span className="small fw-bold text-muted">Remaining Balance:</span>
          <span className="fw-bold text-danger" style={{fontSize: '1.2rem'}}>₹{balance}</span>
        </div>
      </div>
    );
  };

  return (
    <div className="container-fluid py-5 mt-4 px-lg-5" style={{backgroundColor: '#f8f9fa', minHeight: '100vh'}}>
      <div className="text-center mb-5">
        <h2 className="fw-bold" style={{color: '#2c3e50'}}>Live Project Tracker</h2>
        <p className="text-muted">सभी सक्रिय प्रोजेक्ट्स की रीयल-टाइम रिपोर्ट।</p>
      </div>

      {loading ? (
        <div className="text-center py-5">
          <div className="spinner-border text-primary" role="status"></div>
          <p className="mt-2">प्रोजेक्ट लोड हो रहे हैं...</p>
        </div>
      ) : error ? (
        <div className="alert alert-danger text-center shadow-sm">{error}</div>
      ) : (
        <div className="row g-4">
          {projects.length > 0 ? projects.map((proj) => (
            <div className="col-12 mb-4" key={proj._id}>
              <div className="card shadow-sm border-0 rounded-4 overflow-hidden">
                {/* Header Section */}
                <div className="card-header d-flex justify-content-between align-items-center p-3" style={{backgroundColor: '#1a1a1a'}}>
                  <h6 className="mb-0 fw-bold" style={{color: '#ffcc00', letterSpacing: '0.5px'}}>
                    {proj.fullName.toLowerCase()} - <small style={{color: '#ffcc00', opacity: 0.8}}>{proj.serviceType}</small>
                  </h6>
                  <span className="badge px-3 py-2 shadow-sm" style={{backgroundColor: '#ffcc00', color: '#000', fontWeight: 'bold'}}>
                    {proj.status}
                  </span>
                </div>

                <div className="card-body p-4 bg-white">
                  <div className="row align-items-center">
                    {/* 1. Work Progress */}
                    <div className="col-md-4 border-end">
                      <label className="fw-bold small mb-3 text-muted text-uppercase">Work Progress</label>
                      <div className="d-flex align-items-center gap-3">
                        <div className="progress flex-grow-1 shadow-sm" style={{ height: '10px', borderRadius: '10px' }}>
                          <div 
                            className="progress-bar progress-bar-striped progress-bar-animated" 
                            style={{ width: `${proj.progress}%`, backgroundColor: '#007bff' }}
                          ></div>
                        </div>
                        <span className="fw-bold text-primary">{proj.progress}%</span>
                      </div>
                    </div>

                    {/* 2. Payment Summary - सुधारा गया सेक्शन */}
                    <div className="col-md-4 px-4 border-end">
                      <label className="fw-bold small mb-2 text-muted text-uppercase">Payment Summary</label>
                      {renderPaymentStatus(proj)}
                    </div>

                    {/* 3. Revision Request */}
                    <div className="col-md-4 ps-4">
                      <label className="fw-bold small mb-3 text-primary text-uppercase">Request Changes / Revisions</label>
                      <div className="input-group shadow-sm">
                        <input 
                          type="text" id={`rev-${proj._id}`} 
                          className="form-control form-control-sm" 
                          placeholder="बदलाव यहाँ लिखें..." 
                          style={{border: '1px solid #ced4da', padding: '10px'}}
                        />
                        <button 
                          className="btn btn-primary btn-sm fw-bold px-3" 
                          onClick={() => handleRevisionRequest(proj._id)}
                        >
                          Send
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )) : (
            <div className="text-center py-5 text-muted">
              <h5>कोई सक्रिय प्रोजेक्ट नहीं मिला।</h5>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export default ClientDashboard;
